1	/**
2	 * mcp-server.js — MCP HTTP server running inside Electron's main process.
3	 *
4	 * Every read tool auto-refreshes its cache slice from the renderer before
5	 * returning. Contacts+chats refresh is free (Store iteration). Message
6	 * refresh is incremental (skipped when chat.t hasn't moved). The one branch
7	 * that triggers real WhatsApp server requests is get_messages on a cold
8	 * chat, where inject.js loops loadEarlierMsgs.
9	 *
10	 * IPC flow:
11	 *   tool handler → callRenderer → IPC → inject.js → Store API → IPC → cache merge
12	 */
13	
14	import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
15	import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
16	import { isInitializeRequest } from "@modelcontextprotocol/sdk/types.js";
17	import { randomUUID } from "node:crypto";
18	import { readFileSync } from "node:fs";
19	import { join } from "node:path";
20	import express from "express";
21	import cors from "cors";
22	import { z } from "zod";
23	import { app, ipcMain } from "electron";
24	import * as cache from "./cache.js";
25	
26	const ICON_B64 = readFileSync(join(app.getAppPath(), "icon_48x48.png")).toString("base64");
27	
28	const PORT = 39571;
29	
30	// ── Renderer bridge ───────────────────────────────────────────
31	
32	const pendingRequests = new Map();
33	let nextRequestId = 1;
34	
35	let _getWindow = null;
36	let _isReady = null;
37	
38	export function setBridge(getWindowFn, isReadyFn) {
39	  _getWindow = getWindowFn;
40	  _isReady = isReadyFn;
41	}
42	
43	ipcMain.handle("wa:response", (_event, requestId, result, error) => {
44	  const pending = pendingRequests.get(requestId);
45	  if (!pending) return;
46	  pendingRequests.delete(requestId);
47	  if (error) pending.reject(new Error(error));
48	  else pending.resolve(result);
49	});
50	
51	function callRenderer(method, args = []) {
52	  const win = _getWindow?.();
53	  if (!win) return Promise.reject(new Error("WhatsApp window not open"));
54	  if (!_isReady?.()) return Promise.reject(new Error("WhatsApp is still loading — try again in ~15 seconds"));
55	
56	  const requestId = nextRequestId++;
57	  return new Promise((resolve, reject) => {
58	    const timeout = setTimeout(() => {
59	      pendingRequests.delete(requestId);
60	      reject(new Error("Renderer call timed out (15s)"));
61	    }, 15000);
62	
63	    pendingRequests.set(requestId, {
64	      resolve: (result) => { clearTimeout(timeout); resolve(result); },
65	      reject: (err) => { clearTimeout(timeout); reject(err); },
66	    });
67	
68	    win.webContents.send("wa:request", requestId, method, args);
69	  });
70	}
71	
72	// ── Auto-sync helpers ────────────────────────────────────────
73	
74	async function autoSyncContactsChats() {
75	  const [contacts, chats] = await Promise.all([
76	    callRenderer("getContacts"),
77	    callRenderer("getChats"),
78	  ]);
79	  cache.mergeContacts(contacts);
80	  cache.mergeChats(chats);
81	}
82	
83	function resolveSenderNames(messages) {
84	  const mentionMap = cache.getMentionMap();
85	  for (const m of messages) {
86	    const num = (m.from || "").split("@")[0];
87	    if (num && mentionMap[num]) m.sender = mentionMap[num];
88	  }
89	}
90	
91	async function fetchMessagesUntil(chatId, stopAt) {
92	  const all = await callRenderer("getMessagesUntil", [chatId, stopAt]);
93	  return stopAt ? all.filter((m) => m.timestamp > stopAt) : all;
94	}
95	
96	async function autoSyncMessages(chatId, since) {
97	  const newestCached = cache.getNewestCachedMessageTimestamp(chatId);
98	
99	  let fresh;
100	  if (!newestCached) {
101	    fresh = await fetchMessagesUntil(chatId, since);
102	  } else {
103	    const chatTimestamp = cache.getCachedChatTimestamp(chatId);
104	    if (chatTimestamp && chatTimestamp <= newestCached) return;
105	    fresh = await fetchMessagesUntil(chatId, newestCached);
106	  }
107	
108	  if (!fresh || fresh.length === 0) return;
109	  resolveSenderNames(fresh);
110	  cache.mergeMessages(chatId, fresh);
111	}
112	
113	// ── Message formatter ─────────────────────────────────────────
114	
115	const MEDIA_LABELS = {
116	  image: "[image]", video: "[video]", audio: "[audio]",
117	  ptt: "[voice note]", document: "[document]", sticker: "[sticker]",
118	  call_log: "[call]", vcard: "[contact]", location: "[location]",
119	};
120	
121	const DAY_NAMES = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
122	const MONTH_NAMES = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
123	
124	function toLocalTime(utcISO) {
125	  if (!utcISO) return null;
126	  const dt = new Date(utcISO);
127	  const h = dt.getHours();
128	  const m = dt.getMinutes().toString().padStart(2, "0");
129	  const ampm = h >= 12 ? "PM" : "AM";
130	  const h12 = h % 12 || 12;
131	  const month = MONTH_NAMES[dt.getMonth()];
132	  const day = dt.getDate();
133	  return `${month} ${day}, ${h12}:${m} ${ampm}`;
134	}
135	
136	function localizeResults(results) {
137	  return results.map((r) => {
138	    const out = { ...r };
139	    if (out.timestamp) out.timestamp = toLocalTime(out.timestamp);
140	    if (out.lastMessage?.timestamp) {
141	      out.lastMessage = { ...out.lastMessage, timestamp: toLocalTime(out.lastMessage.timestamp) };
142	    }
143	    return out;
144	  });
145	}
146	
147	function formatMessages(messages, chatName, mentionMap = {}) {
148	  const lines = [];
149	  let lastDate = "";
150	
151	  for (const m of messages) {
152	    const dt = new Date(m.timestamp);
153	    const dateKey = `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, "0")}-${String(dt.getDate()).padStart(2, "0")}`;
154	
155	    if (dateKey !== lastDate) {
156	      lastDate = dateKey;
157	      const dayName = DAY_NAMES[dt.getDay()];
158	      const month = MONTH_NAMES[dt.getMonth()];
159	      const day = dt.getDate();
160	      if (lines.length > 0) lines.push("");
161	      lines.push(`-- ${dayName}, ${month} ${day} --`);
162	    }
163	
164	    if (m.type === "pinned_message") continue;
165	
166	    const hours = dt.getHours();
167	    const mins = dt.getMinutes().toString().padStart(2, "0");
168	    const ampm = hours >= 12 ? "PM" : "AM";
169	    const h12 = hours % 12 || 12;
170	    const time = `${h12}:${mins} ${ampm}`;
171	
172	    const fromMe = m.id.startsWith("true_");
173	    const sender = fromMe ? "< You" : `> ${m.sender || chatName}`;
174	
175	    let body = m.body || "";
176	    const label = MEDIA_LABELS[m.type];
177	    if (label && m.type !== "chat") {
178	      if (m.type === "document" && body) body = `[${body}]`;
179	      else body = body ? `${label} ${body}` : label;
180	    }
181	
182	    body = body.replace(/@(\d{5,})/g, (match, num) => {
183	      const name = mentionMap[num];
184	      return name ? `@${name}` : match;
185	    });
186	
187	    lines.push(`${sender} (${time}) -- ${body}`);
188	  }
189	
190	  return lines.join("\n");
191	}
192	
193	// ── MCP server factory ───────────────────────────────────────
194	
195	function createServer() {
196	  const server = new McpServer({
197	    name: "whatsapp",
198	    version: "3.0.0",
199	    icons: [{
200	      src: `data:image/png;base64,${ICON_B64}`,
201	      mimeType: "image/png",
202	      sizes: ["48x48"],
203	    }],
204	    instructions: `To read WhatsApp messages:
205	1. Call whatsapp_list_chats (or whatsapp_list_contacts) to find the chat and grab its id.
206	   - whatsapp_list_chats requires at least one of: query (name/phone substring) or since (ISO timestamp).
207	   - whatsapp_list_contacts requires at least one of: query or tag.
